#!/usr/bin/env dart

import 'dart:io';

import 'package:garmisch/src/generator/generator.dart';

/// Garmisch Design Token Generator CLI
///
/// Generates Dart code from DTCG (Design Tokens Community Group) format JSON files.
///
/// Usage:
///   dart run garmisch:generate_tokens [options]
///
/// Options:
///   --input, -i     Path to the design tokens JSON file (default: design-tokens.json)
///   --output, -o    Output directory for generated files (default: lib/<name>_tokens/)
///   --name, -n      Name prefix for generated classes and files (default: Generated)
///   --help, -h      Show this help message
void main(List<String> arguments) {
  final args = _parseArgs(arguments);

  if (args.showHelp) {
    _printHelp();
    return;
  }

  final inputPath = args.input;
  final outputDir = args.output;
  final prefix = args.name;

  print('🎨 Garmisch Design Token Generator');
  print('');
  print('📄 Input:  $inputPath');
  print('📁 Output: $outputDir');
  print('🏷️  Name:   $prefix');
  print('');

  // Check if input file exists
  final inputFile = File(inputPath);
  if (!inputFile.existsSync()) {
    print('❌ Error: Input file not found: $inputPath');
    print('');
    print('💡 Tip: Copy the default design-tokens.json from the garmisch package:');
    print('   cp <path-to-garmisch>/tokens/design-tokens.json .');
    exit(1);
  }

  // Create output directory if it doesn't exist
  final outputDirectory = Directory(outputDir);
  if (!outputDirectory.existsSync()) {
    outputDirectory.createSync(recursive: true);
    print('📁 Created output directory: $outputDir');
  }

  // Parse tokens
  final warnings = <String>[];
  void onWarning(String message) {
    warnings.add(message);
    print('⚠️  Warning: $message');
  }

  final parser = TokenParser(onWarning: onWarning);

  Map<String, dynamic> tokens;
  try {
    tokens = parser.parseFile(inputPath);
  } catch (e) {
    print('❌ Error parsing tokens: $e');
    exit(1);
  }

  // Create generators
  final generators = <BaseGenerator>[
    ColorGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
    createSpacingGenerator(parser, onWarning: onWarning, prefix: prefix),
    createSizingGenerator(parser, onWarning: onWarning, prefix: prefix),
    createBorderRadiusGenerator(parser, onWarning: onWarning, prefix: prefix),
    createBorderWidthGenerator(parser, onWarning: onWarning, prefix: prefix),
    createBreakpointGenerator(parser, onWarning: onWarning, prefix: prefix),
    createOpacityGenerator(parser, onWarning: onWarning, prefix: prefix),
    DurationGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
    CubicBezierGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
    ShadowGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
    TypographyGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
    ThemeIntegrationGenerator(parser: parser, onWarning: onWarning, prefix: prefix),
  ];

  // Generate files
  var generatedCount = 0;
  for (final generator in generators) {
    try {
      final code = generator.generate(tokens);
      final outputPath = '$outputDir/${generator.fileName}';
      File(outputPath).writeAsStringSync(code);
      print('✅ Generated: ${generator.fileName}');
      generatedCount++;
    } catch (e) {
      print('❌ Error generating ${generator.fileName}: $e');
    }
  }

  // Generate barrel export
  final barrelFileName = _generateBarrelExport(outputDir, generators, prefix);
  print('✅ Generated: $barrelFileName (barrel export)');

  print('');
  print('🎉 Done! Generated $generatedCount files.');

  if (warnings.isNotEmpty) {
    print('');
    print('⚠️  ${warnings.length} warning(s) during generation.');
  }

  print('');
  print('📦 Import in your code:');
  print("   import 'package:your_app/${outputDir.replaceFirst('lib/', '')}/$barrelFileName';");
}

String _toSnakeCase(String input) {
  return input
      .replaceAllMapped(
        RegExp(r'([A-Z])'),
        (match) => '_${match.group(1)!.toLowerCase()}',
      )
      .replaceFirst(RegExp(r'^_'), '')
      .toLowerCase();
}

String _generateBarrelExport(String outputDir, List<BaseGenerator> generators, String prefix) {
  final snakePrefix = _toSnakeCase(prefix);
  final barrelFileName = '${snakePrefix}.dart';

  final buffer = StringBuffer();
  buffer.writeln('// GENERATED CODE - DO NOT MODIFY BY HAND');
  buffer.writeln('// Generated by garmisch token generator');
  buffer.writeln();
  buffer.writeln('/// Generated design tokens barrel export');
  buffer.writeln('library $snakePrefix;');
  buffer.writeln();

  for (final generator in generators) {
    buffer.writeln("export '${generator.fileName}';");
  }

  final outputPath = '$outputDir/$barrelFileName';
  File(outputPath).writeAsStringSync(buffer.toString());

  return barrelFileName;
}

class _Args {
  _Args({
    required this.input,
    required this.output,
    required this.name,
    required this.showHelp,
  });

  final String input;
  final String output;
  final String name;
  final bool showHelp;
}

_Args _parseArgs(List<String> arguments) {
  var input = 'design-tokens.json';
  String? output;
  var name = 'Generated';
  var showHelp = false;

  for (var i = 0; i < arguments.length; i++) {
    final arg = arguments[i];

    switch (arg) {
      case '--help':
      case '-h':
        showHelp = true;
        break;
      case '--input':
      case '-i':
        if (i + 1 < arguments.length) {
          input = arguments[++i];
        }
        break;
      case '--output':
      case '-o':
        if (i + 1 < arguments.length) {
          output = arguments[++i];
        }
        break;
      case '--name':
      case '-n':
        if (i + 1 < arguments.length) {
          name = arguments[++i];
        }
        break;
      default:
        if (arg.startsWith('--input=')) {
          input = arg.substring('--input='.length);
        } else if (arg.startsWith('--output=')) {
          output = arg.substring('--output='.length);
        } else if (arg.startsWith('--name=')) {
          name = arg.substring('--name='.length);
        } else if (arg.startsWith('-i=')) {
          input = arg.substring('-i='.length);
        } else if (arg.startsWith('-o=')) {
          output = arg.substring('-o='.length);
        } else if (arg.startsWith('-n=')) {
          name = arg.substring('-n='.length);
        }
    }
  }

  // Compute output directory from name if not provided
  final snakeName = name
      .replaceAllMapped(
        RegExp(r'([A-Z])'),
        (match) => '_${match.group(1)!.toLowerCase()}',
      )
      .replaceFirst(RegExp(r'^_'), '')
      .toLowerCase();
  final effectiveOutput = output ?? 'lib/${snakeName}_tokens';

  return _Args(
    input: input,
    output: effectiveOutput,
    name: name,
    showHelp: showHelp,
  );
}

void _printHelp() {
  print('''
🎨 Garmisch Design Token Generator

Generates Dart code from DTCG (Design Tokens Community Group) format JSON files.

USAGE:
  dart run garmisch:generate_tokens [options]

OPTIONS:
  --input, -i <path>    Path to the design tokens JSON file
                        (default: design-tokens.json)

  --output, -o <path>   Output directory for generated files
                        (default: lib/<name>_tokens, e.g., lib/generated_tokens)

  --name, -n <name>     Name prefix for generated classes and files
                        (default: Generated)
                        This affects both the output folder (if not specified)
                        and the generated class/file names.
                        Example: --name=Acme generates:
                        - Folder: lib/acme_tokens/
                        - Classes: AcmeColors, AcmeSpacing, AcmeTheme, etc.
                        - Files: acme_colors.g.dart, acme_spacing.g.dart, etc.
                        - Barrel: acme.dart

  --help, -h            Show this help message

EXAMPLES:
  # Generate with defaults (lib/generated_tokens/)
  dart run garmisch:generate_tokens

  # Custom input and output
  dart run garmisch:generate_tokens -i tokens/my-tokens.json -o lib/theme/tokens

  # Custom name prefix (generates to lib/acme_tokens/)
  dart run garmisch:generate_tokens --name=Acme

  # Custom name with custom output directory
  dart run garmisch:generate_tokens --name=MyBrand --output=lib/design_system

DTCG FORMAT:
  The input file should follow the Design Tokens Community Group format.
  See: https://tr.designtokens.org/format/

  Example token:
  {
    "color": {
      "primary": {
        "\$type": "color",
        "\$value": "#3B82F6"
      }
    }
  }

CUSTOM FONTS:
  To use custom fonts, define them in your design-tokens.json:

  {
    "fontFamily": {
      "heading": { "\$type": "fontFamily", "\$value": "Poppins" },
      "body": { "\$type": "fontFamily", "\$value": "Open Sans" }
    }
  }

  Then register the fonts in your pubspec.yaml:

  flutter:
    fonts:
      - family: Poppins
        fonts:
          - asset: fonts/Poppins-Regular.ttf
          - asset: fonts/Poppins-Bold.ttf
            weight: 700

For more information, visit: https://github.com/your-org/garmisch
''');
}

